import {
  Container,
  Typography,
  Card,
  CardContent,
  Box,
  AppBar,
  Toolbar,
  Button,
} from "@mui/material";

import "./BoardPage.css";

function BoardPage() {
  const posts = [
    {
      id: 1,
      title: "공지사항",
      author: "관리자",
      content: "게시판 테스트입니다.",
    },
    {
      id: 2,
      title: "React 공부",
      author: "홍길동",
      content: "Material UI와 CSS를 적용 중입니다.",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드와 API 연결 예정입니다.",
    },
  ];

  return (
    <>
      {/* Navbar */}
      <AppBar
        position="static"
        className="navbar"
        elevation={0}
      >
        <Toolbar className="navbar-toolbar">

          {/* 왼쪽 로고/제목 */}
          <Box sx={{ display: "flex", alignItems: "center" }}>
            <img
              src="/kw_logo.png"
              alt="logo"
              className="navbar-logo"
            />
          </Box>

          {/* 오른쪽 버튼 영역 */}
          <Box sx={{ marginLeft: "auto" }}>

            <Button className="nav-button">
              게시물 등록
            </Button>

            <Button className="nav-button logout-btn">
              로그아웃
            </Button>

          </Box>
        </Toolbar>
      </AppBar>


      {/* 게시판 영역 */}
      <Container className="board-container">

        {/* 게시글 카드 */}
        {posts.map((post) => (
          <Card
            key={post.id}
            className="board-card"
            sx={{ mb: 3 }}
          >
            <CardContent>

              <Typography
                variant="h5"
                className="board-post-title"
              >
                {post.title}
              </Typography>

              <Typography className="board-author">
                작성자: {post.author}
              </Typography>

              <Typography className="board-content">
                {post.content}
              </Typography>

            </CardContent>
          </Card>
        ))}
      </Container>
    </>
  );
}

export default BoardPage;
